import React from "react";
import FurnitureOne from "../../../Asserts/FurnitureOne.png";
import FurnitureTwo from "../../../Asserts/FurnitureTwo.png";
import FurnitureThree from "../../../Asserts/FurnitureThree.png";
import FurnitureFour from "../../../Asserts/FurnitureFour.png";
import Styles from "./Section.module.css";



const SectionA: React.FC = () => {



  return (
    <div className={Styles.SectionAContainerMain}>
      <div className={Styles.SectionAContainer}>
        <div className={Styles.SectionImage}>
          <img src={FurnitureOne} alt="Furniture One" />
        </div>
        <div className={Styles.SectionImages}>
          <div className={Styles.ImageOne}>
          <img src={FurnitureTwo} alt="Furniture Two" />
          </div>
          <div className={Styles.ImageTwo}>
            <div className={Styles.ImageChild}>
            <img src={FurnitureThree} alt="Furniture Three" />
            </div>
            <div className={Styles.ImageChild}>
            <img src={FurnitureFour} alt="Furniture Four" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default SectionA;
